// src/pages/Signup.js
import React, { useState } from "react";
import { useAuth } from "../context/AuthContext";
import { useNavigate, Link } from "react-router-dom";

export default function Signup() {
  const { signup, googleLogin } = useAuth();
  const [email, setEmail] = useState("");
  const [name, setName] = useState("");
  const [password, setPassword] = useState("");
  const [showPw, setShowPw] = useState(false);
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const onSubmit = async (e) => {
    e.preventDefault();
    setErr("");
    setLoading(true);
    try {
      await signup(email, password);
      // optionally save displayName to profile here
      navigate("/dashboard");
    } catch (error) {
      setErr(error.message || "Signup failed");
    } finally {
      setLoading(false);
    }
  };

  const handleGoogle = async () => {
    try {
      await googleLogin();
      navigate("/dashboard");
    } catch (err) {
      setErr(err.message || "Google signup failed");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4">
      <div className="w-full max-w-md bg-white dark:bg-gray-900 rounded-xl p-6 shadow-lg">
        <h2 className="text-2xl font-bold mb-3 text-primary dark:text-white">Create account</h2>
        {err && <div className="mb-3 text-sm text-red-500">{err}</div>}
        <form onSubmit={onSubmit} className="space-y-3">
          <input value={name} onChange={(e)=>setName(e.target.value)} placeholder="Full name" className="w-full px-3 py-2 border rounded" />
          <input value={email} onChange={(e)=>setEmail(e.target.value)} type="email" placeholder="Email" className="w-full px-3 py-2 border rounded" required />
          <div className="relative">
            <input value={password} onChange={(e)=>setPassword(e.target.value)} type={showPw ? "text" : "password"} placeholder="Password" className="w-full px-3 py-2 border rounded" required />
            <button type="button" onClick={() => setShowPw(s=>!s)} className="absolute right-2 top-2 text-sm">{showPw ? "Hide" : "Show"}</button>
          </div>

          <button disabled={loading} type="submit" className="w-full bg-yellow-400 text-black py-2 rounded">
            {loading ? "Creating..." : "Sign up"}
          </button>
        </form>

        <div className="my-4 flex items-center">
          <hr className="flex-grow" />
          <span className="px-2 text-sm text-gray-500">OR</span>
          <hr className="flex-grow" />
        </div>

        <button onClick={handleGoogle} className="w-full border py-2 rounded flex items-center justify-center space-x-2">
          <img src="https://upload.wikimedia.org/wikipedia/commons/5/53/Google_%22G%22_Logo.svg" alt="G" className="w-5 h-5" />
          <span>Sign up with Google</span>
        </button>

        <div className="mt-3 text-sm text-center">
          Already have an account? <Link to="/login" className="text-yellow-500">Login</Link>
        </div>
      </div>
    </div>
  );
}
